{"path": "/tmp/sv-5e77693bbba947d689a6807ba4edca88/Components/Chat/MessageInput.razor", "file_text": "<div class="message-input">
    <textarea class="message-textarea"
              @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="1"></textarea>
    <button class="send-button" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        var content = Text.Trim();
        if (string.IsNullOrEmpty(content)) return;
        Text = string.Empty;
        await OnSubmit.InvokeAsync(content);
    }
}
"}

