arguments.file_text:
namespace sv_5e77693bbba947d689a6807ba4edca88.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_5e77693bbba947d689a6807ba4edca88.Services

<div class="message-bubble @(IsThreadStarter ? "thread-starter" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (IsThreadStarter)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message)">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message)" title="Reply in thread">
                💬
            </button>
            <div class="react-wrapper">
                <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                    😀
                </button>
                @if (_showEmojiPicker)
                {
                    <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool IsThreadStarter { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void OnMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

.message-bubble {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
}

.message-bubble:hover {
    background: rgba(255, 255, 255, 0.03);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 4px;
}

.author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    color: #dcddde;
    font-size: 0.9rem;
    line-height: 1.4;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: rgba(88, 101, 242, 0.15);
    border: 1px solid rgba(88, 101, 242, 0.3);
    border-radius: 6px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #dcddde;
    cursor: default;
}

.thread-link {
    background: transparent;
    border: none;
    color: #5865f2;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 4px;
    font-family: inherit;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #1e1f22;
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.action-btn {
    background: transparent;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.action-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

.react-wrapper {
    position: relative;
}

