                           OnReact="OnReact" />
        }
        <div @ref="_scrollAnchor"></div>
    </div>

    <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                  ButtonLabel="Send"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, (int ReplyCount, DateTime LastReplyAt)> ThreadSummaries { get; set; } = new();
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private ElementReference _scrollContainer;
    private ElementReference _scrollAnchor;
    private bool _shouldScrollToBottom = true;
    private int _previousMessageCount;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_shouldScrollToBottom)
        {
            _shouldScrollToBottom = false;
            await JS.InvokeVoidAsync("eval", "document.querySelector('[b-message-area-anchor]')?.scrollIntoView?.() || arguments[0]?.scrollIntoView?.()", _scrollAnchor);
        }
    }

    protected override void OnParametersSet()
    {
        if (Messages.Count != _previousMessageCount && Messages.Count > 0)
        {
            // Scroll to bottom when new messages arrive (not on load-more)
            if (_previousMessageCount == 0 || Messages.Count == _previousMessageCount + 1)
            {
                _shouldScrollToBottom = true;
            }
            _previousMessageCount = Messages.Count;
        }
    }

    private async Task HandleScroll()
    {
        // Detect scroll-to-top for pagination
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50 && HasMoreMessages && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

