toolArgs.file_text:
@using sv_5e77693bbba947d689a6807ba4edca88.Services

<aside class="thread-panel">
    <header class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </header>

    <div class="thread-root-quote">
        <span class="quote-author">@RootMessage.Author</span>
        <p class="quote-content">@RootMessage.Content</p>
    </div>

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="author">@reply.Author</span>
                    <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="reply-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply…"
                  ButtonLabel="Reply"
                  OnSubmit="OnSendReply" />
</aside>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2b2d31;
    border-left: 1px solid rgba(255, 255, 255, 0.06);
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    background: transparent;
    border: none;
    color: #888;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: rgba(255, 255, 255, 0.1);
    color: #fff;
}

.thread-root-quote {
    padding: 12px 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
    border-left: 3px solid #5865f2;
    margin: 12px 16px;
    border-radius: 0 4px 4px 0;
    background: rgba(255, 255, 255, 0.02);
}

.quote-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.85rem;
}

.quote-content {
    color: #a0a0a0;
    font-size: 0.85rem;
    margin: 4px 0 0;
    line-height: 1.4;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.thread-reply:hover {
    background: rgba(255, 255, 255, 0.03);
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-header .author {
    font-weight: 600;
    color: #fff;
    font-size: 0.85rem;
}

.reply-header .timestamp {
    font-size: 0.7rem;
    color: #72767d;
}

.reply-content {
    color: #dcddde;
    font-size: 0.85rem;
    line-height: 1.4;
}

